mapper.select:
select count(*)
from information_schema.tables
where table_schema = current_schema() and table_name = #{tableName}

select count(*)
from information_schema.columns
where table_schema = current_schema()
  and table_name = #{tableName}
  and column_name = #{columnName}

select count(*)
from pg_indexes
where schemaname = current_schema() and indexname = #{indexName}

select r.id, r.volume_id, r.fonds_code, r.fonds_name, r.category_code, r.category_name, r.archive_no, r.electronic_status, r.archive_year, r.display_order, r.created_at, r.locked_flag, r.lock_reason, r.locked_by, r.locked_at ${selectColumns} from am_archive_item r join ${tableName} d on d.id = r.id where r.deleted_flag = false and d.deleted_flag = false
and #{userId} is not null
and r.fonds_code = #{fondsCode}
and d.${condition.columnName} = #{condition.value}
and d.${condition.columnName} >= #{condition.value}
and d.${condition.columnName} <= #{condition.value}
and exists ( select 1 from am_archive_item_search s where s.archive_item_id = r.id and ( s.search_text ilike '%' || replace(replace(#{fullTextKeyword}, '%', '\%'), '_', '\_') || '%' escape '\' or s.search_text % #{fullTextKeyword} ) )
and (${cursorPredicateSql})
order by ${orderBySql} limit #{limit}

mapper.update:
update ${tableName}
set

    ${assignment.columnName} = #{assignment.value}

    , updated_at = localtimestamp
where id = #{id} and deleted_flag = false

update ${tableName}
set deleted_flag = true, updated_at = localtimestamp
where id = #{id} and deleted_flag = false

mapper.select:
select *
from ${tableName}
where id = #{id} and deleted_flag = false

select id, fonds_code, fonds_name, category_code, category_name, archive_no, electronic_status, archive_year, locked_flag, lock_reason, locked_by, locked_at from am_archive_volume where deleted_flag = false
and fonds_code = #{fondsCode}
and category_code = #{categoryCode}
order by sort_order, id desc

select *
from ${tableName}
where item_id = #{itemId}
  and deleted_flag = false
order by line_order, id
